import{_ as t,c as a,o as e,d as r}from"./app.cb576e3f.js";const u='{"title":"\u041A\u0430\u043C\u0435\u043D\u044C, \u043D\u043E\u0436\u043D\u0438\u0446\u044B, \u0431\u0443\u043C\u0430\u0433\u0430. \u0420\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u2013 \u0431\u0438\u0437\u043D\u0435\u0441 \u0434\u043B\u044F \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439","description":"","frontmatter":{"title":"\u041A\u0430\u043C\u0435\u043D\u044C, \u043D\u043E\u0436\u043D\u0438\u0446\u044B, \u0431\u0443\u043C\u0430\u0433\u0430. \u0420\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u2013 \u0431\u0438\u0437\u043D\u0435\u0441 \u0434\u043B\u044F \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439","date":"2016-02-18","cover":"cover.jpg"},"headers":[{"level":2,"title":"\u0423\u0440\u043E\u043A\u0438 \u0442\u0440\u0443\u0434\u0430","slug":"\u0443\u0440\u043E\u043A\u0438-\u0442\u0440\u0443\u0434\u0430"},{"level":2,"title":"\u0421\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438","slug":"\u0441\u0432\u043E\u0438\u043C\u0438-\u0440\u0443\u043A\u0430\u043C\u0438"},{"level":2,"title":"\u0420\u0430\u0434\u043E\u0441\u0442\u044C \u0442\u0440\u0443\u0434\u0430","slug":"\u0440\u0430\u0434\u043E\u0441\u0442\u044C-\u0442\u0440\u0443\u0434\u0430"}],"relativePath":"theory/repost/rock-paper-scissors/index.md"}',p={},o=r('<p>\u0414\u0435\u043B\u043E\u0432\u043E\u0439 \u0435\u0436\u0435\u043D\u0435\u0434\u0435\u043B\u044C\u043D\u0438\u043A \xAB\u041A\u043E\xBB \u0432\u044B\u044F\u0441\u043D\u0438\u043B, \u043A\u0430\u043A \u0432 \u041C\u043E\u0441\u043A\u0432\u0435 \u0438 \u0421\u0430\u043D\u043A\u0442-\u041F\u0435\u0442\u0435\u0440\u0431\u0443\u0440\u0433\u0435 \u0437\u0430\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u044E\u0442 \u043D\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C \u0441\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438. \u0421\u0442\u0430\u0442\u044C\u044F \u043D\u0430\u0441\u044B\u0449\u0435\u043D\u0430 \u0446\u0438\u0444\u0440\u0430\u043C\u0438 \u0438 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u044B\u043C\u0438 \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u0430\u043C\u0438 \u043E \u043F\u0443\u0442\u0438 \u043F\u0435\u0440\u0432\u043E\u043F\u0440\u043E\u0445\u043E\u0434\u0446\u0435\u0432 \u2014 \u0441\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u0435\u0439 \u043F\u0435\u0440\u0432\u044B\u0445\xA0\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445 \u0432 \u0420\u043E\u0441\u0441\u0438\u0438.</p><p><strong>\u0421\u043D\u0430\u0447\u0430\u043B\u0430 \u043D\u0430 \u0440\u043E\u0441\u0441\u0438\u0439\u0441\u043A\u043E\u043C \u0440\u044B\u043D\u043A\u0435 \u043F\u043E\u044F\u0432\u0438\u043B\u0438\u0441\u044C \u043E\u0444\u0438\u0441\u043D\u044B\u0435 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0438, \u0441\u043B\u0435\u0434\u043E\u043C \u2013 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0435. \u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u043D\u044E\u0430\u043D\u0441\u044B, \u0438\u0434\u0435\u044F \u0432 \u043F\u0435\u0440\u0432\u043E\u043C \u0438 \u0432\u043E \u0432\u0442\u043E\u0440\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0434\u043D\u0430 \u0438 \u0442\u0430 \u0436\u0435\xA0\u2013 \u0441\u0434\u0430\u0432\u0430\u0442\u044C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0440\u0430\u0431\u043E\u0447\u0435\u0435 \u043C\u0435\u0441\u0442\u043E \u0432 \u0430\u0440\u0435\u043D\u0434\u0443 \u043D\u0430 \u043B\u044E\u0431\u043E\u0439 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A \u0432\u0440\u0435\u043C\u0435\u043D\u0438.</strong></p><h2 id="\u0443\u0440\u043E\u043A\u0438-\u0442\u0440\u0443\u0434\u0430" tabindex="-1">\u0423\u0440\u043E\u043A\u0438 \u0442\u0440\u0443\u0434\u0430 <a class="header-anchor" href="#\u0443\u0440\u043E\u043A\u0438-\u0442\u0440\u0443\u0434\u0430" aria-hidden="true">#</a></h2><p>\u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043D\u0430\u0437\u0430\u0434 \u0432 \u0421\u0430\u043D\u043A\u0442-\u041F\u0435\u0442\u0435\u0440\u0431\u0443\u0440\u0433\u0435 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \xAB\u041A\u043B\u0430\u0441\u0441 \u0442\u0440\u0443\u0434\u0430\xBB \u043F\u043E\u0437\u0438\u0446\u0438\u043E\u043D\u0438\u0440\u0443\u0435\u0442 \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u043F\u0435\u0440\u0432\u0430\u044F \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F, \u0433\u0434\u0435 \u0435\u0441\u0442\u044C \u0432\u0441\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0435 \u0434\u043B\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0441 \u0434\u0435\u0440\u0435\u0432\u043E\u043C, \u0441\u0442\u0435\u043A\u043B\u043E\u043C, \u043A\u0435\u0440\u0430\u043C\u0438\u043A\u043E\u0439 \u0438 \u043A\u043E\u0436\u0435\u0439. \u042D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u043D\u0430 \u043F\u0435\u0440\u0432\u043E\u043C \u044D\u0442\u0430\u0436\u0435 \u0432 \u0433\u0430\u0437\u0433\u043E\u043B\u044C\u0434\u0435\u0440\u0435, \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u043D\u043E\u043C \u0432 1902 \u0433. \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u0444\u0440\u0430\u043D\u0446\u0443\u0437\u0441\u043A\u043E\u0433\u043E \u0433\u0430\u0437\u043E\u0432\u043E\u0433\u043E \u0437\u0430\u0432\u043E\u0434\u0430, \u0441 \u0447\u0435\u0442\u044B\u0440\u044C\u043C\u044F \u0437\u0430\u043B\u0430\u043C\u0438 \u0438 \u0432\u0445\u043E\u0434\u043D\u044B\u043C \u0431\u0438\u043B\u0435\u0442\u043E\u043C \u0432 1000\xA0\u0440\u0443\u0431. \u0437\u0430 \u0434\u0435\u043D\u044C. \u0421\u043E\u0437\u0434\u0430\u0432\u0448\u0438\u0439 \u0435\u0433\u043E \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C \u0414\u0435\u043D\u0438\u0441 \u0413\u0443\u0442\u043E\u0432 \u043F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E \u0434\u0443\u043C\u0430\u043B \u043E \u0441\u0432\u043E\u0435\u0439 \u0436\u0435\u043D\u0435 \u0422\u0430\u0438\u0441\u0438\u0438 \u0411\u043E\u0433\u0430\u0442\u044B\u0440\u0435\u0432\u043E\u0439. \u041A\u043E\u0433\u0434\u0430 \u0435\u0435 \u0443\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435 \u0445\u0435\u043D\u0434\u043C\u0435\u0439\u0434\u043E\u043C \u0432\u044B\u0448\u043B\u043E \u0437\u0430 \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u044B \u043A\u0443\u0445\u043D\u0438, \u043E\u043D \u043F\u0440\u0438\u043D\u044F\u043B\u0441\u044F \u0438\u0441\u043A\u0430\u0442\u044C \u043C\u0435\u0441\u0442\u043E \u0434\u043B\u044F \u043C\u0438\u043D\u0438-\u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u0412\xA0\u0445\u043E\u0434\u0435 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433\u0430 \u0413\u0443\u0442\u043E\u0432 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u043B, \u0447\u0442\u043E \u0432 \u0421\u0428\u0410 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043C\u0430\u0441\u0441\u0430 \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u043E\u0432, \u0430 \u0432 \u0420\u043E\u0441\u0441\u0438\u0438 \u0438\u0445 \u043D\u0435\u0442. \xAB\u041D\u0430 \u0417\u0430\u043F\u0430\u0434\u0435 \u044D\u0442\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u0442\u0443\u0434\u0438\u0438 \u043B\u0438\u0431\u043E \u0446\u0435\u043B\u044B\u0435 \u0446\u0435\u0445\u0430, \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u043C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435\u043C. \u041E\u0441\u0442\u0430\u0432\u0430\u043B\u043E\u0441\u044C \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0430\u0434\u0430\u043F\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043A \u043D\u0430\u0448\u0438\u043C \u0440\u0435\u0430\u043B\u0438\u044F\u043C \u0438 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C \u044D\u0442\u0443 \u0437\u0430\u043E\u043A\u0435\u0430\u043D\u0441\u043A\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C\xBB,\u2009\u2013 \u043F\u043E\u044F\u0441\u043D\u044F\u0435\u0442 \u0414\u0435\u043D\u0438\u0441. \u0415\u0433\u043E \u0440\u0430\u0441\u0447\u0435\u0442 \u043E\u043F\u0440\u0430\u0432\u0434\u0430\u043B\u0441\u044F: \u043D\u0430 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u0443\u044E \u043E\u043A\u0443\u043F\u0430\u0435\u043C\u043E\u0441\u0442\u044C \xAB\u041A\u043B\u0430\u0441\u0441 \u0442\u0440\u0443\u0434\u0430\xBB \u0432\u044B\u0448\u0435\u043B \u043C\u0435\u043D\u044C\u0448\u0435 \u0447\u0435\u043C \u0437\u0430 \u0433\u043E\u0434, \u0438 \u0441 \u043A\u0430\u0436\u0434\u044B\u043C \u0433\u043E\u0434\u043E\u043C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u0443\u0434\u0432\u0430\u0438\u0432\u0430\u0435\u0442 \u0441\u0432\u043E\u0439 \u043E\u0431\u043E\u0440\u043E\u0442.</p><p>\u0414\u043E \u0442\u043E\u0433\u043E \u043A\u0430\u043A \u043E\u0442\u043A\u0440\u044B\u0442\u044C \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0443\u044E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0443\u044E, \u0432\u044B\u043F\u0443\u0441\u043A\u043D\u0438\u043A \u0421\u0430\u043D\u043A\u0442-\u041F\u0435\u0442\u0435\u0440\u0431\u0443\u0440\u0433\u0441\u043A\u043E\u0433\u043E \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0442\u043E\u0440\u0433\u043E\u0432\u043E\u2011\u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0430 \u0438 \u041C\u0435\u0436\u0434\u0443\u043D\u0430\u0440\u043E\u0434\u043D\u043E\u0433\u043E \u0431\u0430\u043D\u043A\u043E\u0432\u0441\u043A\u043E\u0433\u043E \u0438\u043D\u0441\u0442\u0438\u0442\u0443\u0442\u0430 \u0414\u0435\u043D\u0438\u0441 \u0413\u0443\u0442\u043E\u0432 \u0440\u0430\u0431\u043E\u0442\u0430\u043B \u0432 \u0442\u043E\u0440\u0433\u043E\u0432\u043B\u0435 \u0438 \u0431\u0430\u043D\u043A\u043E\u0432\u0441\u043A\u043E\u0439 \u0441\u0444\u0435\u0440\u0435. \u0412\xA02012\xA0\u0433. \u043E\u043D \u0437\u0430\u043D\u044F\u043B\u0441\u044F \u0431\u0438\u0437\u043D\u0435\u0441- \u0438\xA0\u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u043C \u043A\u043E\u043D\u0441\u0430\u043B\u0442\u0438\u043D\u0433\u043E\u043C. \xAB\u042F \u0447\u0430\u0441\u0442\u043E \u0438 \u043C\u043D\u043E\u0433\u043E \u043A\u043E\u043D\u0441\u0443\u043B\u044C\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0441\u0442\u0430\u0440\u0442\u0430\u043F\u044B \u0432 \u041F\u0438\u0442\u0435\u0440\u0435, \u0447\u0442\u043E \u0432 \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u043C\u043E\u043C\u0435\u043D\u0442 \u0440\u0435\u0448\u0438\u043B: \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u043F\u0440\u043E\u0435\u043A\u0442\xA0\u2013 \u044D\u0442\u043E \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u0439 \u0432\u044B\u0437\u043E\u0432\xBB,\u2009\u2013 \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043E\u043D. \u041F\u0435\u0440\u0432\u044B\u0439 \u043E\u043F\u044B\u0442 \u0432 \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0435 \u043E\u043A\u0430\u0437\u0430\u043B\u0441\u044F \u043D\u0435 \u0441\u043E\u0432\u0441\u0435\u043C \u0443\u0434\u0430\u0447\u043D\u044B\u043C \u2013 \u0437\u0430\u043F\u0443\u0449\u0435\u043D\u043D\u044B\u0439 IT-\u0441\u0442\u0430\u0440\u0442\u0430\u043F \u043D\u0435 \u0432\u044B\u0441\u0442\u0440\u0435\u043B\u0438\u043B, \u0430 \u044D\u043D\u0442\u0443\u0437\u0438\u0430\u0437\u043C \u0431\u043E\u0440\u043E\u0442\u044C\u0441\u044F \u0437\u0430 \u043D\u0435\u0433\u043E \u0438\u0441\u0441\u044F\u043A. \u0413\u0443\u0442\u043E\u0432 \u0441\u0442\u0430\u043B \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u0435\u0435 \u043F\u0440\u0438\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u043A \u0441\u0444\u0435\u0440\u0435 \u0440\u0443\u0447\u043D\u043E\u0433\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430. \u041F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0439 \u0438\u043C \u0430\u043D\u0430\u043B\u0438\u0437 \u043F\u043E\u043A\u0430\u0437\u0430\u043B: \u0432 \u041F\u0438\u0442\u0435\u0440\u0435 \u043D\u0435\u0442 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 \u0434\u043B\u044F \u043B\u044E\u0434\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043B\u044E\u0431\u044F\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C.</p><p>\u041D\u0430 \u0437\u0430\u043F\u0443\u0441\u043A \xAB\u041A\u043B\u0430\u0441\u0441\u0430 \u0442\u0440\u0443\u0434\u0430\xBB \u0414\u0435\u043D\u0438\u0441 \u0438 \u0422\u0430\u0438\u0441\u0438\u044F \u043F\u043E\u0442\u0440\u0430\u0442\u0438\u043B\u0438 \u043B\u0438\u0447\u043D\u044B\u0435 \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u044F \u0432 \u0440\u0430\u0437\u043C\u0435\u0440\u0435 500\u2009000\u2013600\u2009000\xA0\u0440\u0443\u0431. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u0443\u0448\u043B\u0438 \u043D\u0430 \u0440\u0435\u043C\u043E\u043D\u0442 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F, \u043F\u043E\u043A\u0443\u043F\u043A\u0443 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043D\u0430 \u0430\u0440\u0435\u043D\u0434\u0443 \u0432 \u043F\u0435\u0440\u0432\u044B\u0435 \u043F\u043E\u043B\u0433\u043E\u0434\u0430 \u2013 \u0442\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0435\u043A\u0442 \u0435\u0449\u0435 \u043D\u0435 \u0440\u0430\u0441\u043A\u0440\u0443\u0442\u0438\u043B\u0441\u044F, \u0438 \u043F\u043E\u0442\u043E\u043A\u0430 \u043A\u043B\u0438\u0435\u043D\u0442\u0441\u043A\u0438\u0445 \u0434\u0435\u043D\u0435\u0433 \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u043B\u043E \u043D\u0430 \u043F\u043E\u043A\u0440\u044B\u0442\u0438\u0435 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u0440\u0430\u0441\u0445\u043E\u0434\u043E\u0432. \u041F\u043E\u043D\u044F\u0432, \u0447\u0442\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0431\u0435\u0437 \u0437\u0430\u0442\u0440\u0430\u0442, \u0441\u0443\u043F\u0440\u0443\u0433\u0438 \u043F\u0440\u043E\u0434\u0430\u043B\u0438 \u0441\u0432\u043E\u044E \u043A\u0432\u0430\u0440\u0442\u0438\u0440\u0443. \u0421\u043F\u0443\u0441\u0442\u044F \u0433\u043E\u0434 \u0440\u0430\u0437\u043D\u043E\u0433\u043B\u0430\u0441\u0438\u044F \u0441 \u0430\u0440\u0435\u043D\u0434\u043E\u0434\u0430\u0442\u0435\u043B\u044F\u043C\u0438 \u0432\u044B\u043D\u0443\u0434\u0438\u043B\u0438 \xAB\u041A\u043B\u0430\u0441\u0441 \u0442\u0440\u0443\u0434\u0430\xBB \u0441\u043C\u0435\u043D\u0438\u0442\u044C \u043C\u0435\u0441\u0442\u043E \u0434\u0438\u0441\u043B\u043E\u043A\u0430\u0446\u0438\u0438. \u041D\u0430 \u043F\u043E\u0438\u0441\u043A\u0438 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F \u0443\u0448\u043B\u043E \u0434\u0432\u0430 \u043C\u0435\u0441\u044F\u0446\u0435\u0432. \u041F\u0440\u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433\u0435 \u0434\u043B\u044F \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u0439 \u0431\u044B\u043B\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0438\u0430\u043B\u044C\u043D\u044B \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0430\u0440\u0430\u043C\u0435\u0442\u0440\u044B \u2013 \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0432 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043C\u0430\u0445, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0448\u0443\u043C\u043D\u044B\u0445 \u0438\xA0\u043F\u044B\u043B\u044C\u043D\u044B\u0445 \u0440\u0430\u0431\u043E\u0442, \u0432\u044B\u0441\u043E\u043A\u0438\u0435 \u043F\u043E\u0442\u043E\u043B\u043A\u0438 \u0438\xA0\u043C\u043D\u043E\u0433\u043E \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0432\u0435\u0442\u0430, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0431\u043B\u0438\u0437\u043A\u043E\u0435 \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043A \u0446\u0435\u043D\u0442\u0440\u0443 \u0433\u043E\u0440\u043E\u0434\u0430 \u0438 \u0448\u0430\u0433\u043E\u0432\u0430\u044F \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u043E\u0442 \u043C\u0435\u0442\u0440\u043E. \u0418\u0437 \u0432\u0441\u0435\u0445 \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u043E\u0432 \u043F\u043E \u0446\u0435\u043D\u0435 \u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0443 \u043F\u043E\u0434\u043E\u0448\u043B\u043E \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u043D\u0430 \u043F\u0435\u0440\u0432\u043E\u043C \u044D\u0442\u0430\u0436\u0435 \u0432 \u0433\u0430\u0437\u0433\u043E\u043B\u044C\u0434\u0435\u0440\u0435 \u043D\u0430 \u0413\u0430\u0437\u043E\u0432\u043E\u0439 \u0443\u043B\u0438\u0446\u0435 \u043F\u043B\u043E\u0449\u0430\u0434\u044C\u044E 370 \u043A\u0432.\u2009\u043C. \u041E\u0441\u0442\u0430\u0442\u043A\u0438 \u0441\u0431\u0435\u0440\u0435\u0436\u0435\u043D\u0438\u0439 \u043E\u0442 \u043F\u0440\u043E\u0434\u0430\u043D\u043D\u043E\u0439 \u043A\u0432\u0430\u0440\u0442\u0438\u0440\u044B \u0443\u0448\u043B\u0438 \u043D\u0430 \u0440\u0435\u043C\u043E\u043D\u0442 \u043D\u043E\u0432\u043E\u0433\u043E \u0437\u0430\u043B\u0430.</p><p>\xAB\u041C\u043D\u043E\u0433\u0438\u0435 \u0434\u0443\u043C\u0430\u044E\u0442 \u0447\u0442\u043E \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\xA0\u2013 \u044D\u0442\u043E \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0439 \u0431\u0438\u0437\u043D\u0435\u0441. \u041E\u043D \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C \u043C\u043E\u0434\u0435\u043B\u044C, \u043F\u043E \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u0443\u0435\u0442 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u0415\u0435 \u0431\u0438\u0437\u043D\u0435\u0441\xA0\u2013 \u0442\u0430\u043A\u043E\u0439 \u0436\u0435, \u043A\u0430\u043A \u0438 \u043B\u044E\u0431\u043E\u0439 \u0434\u0440\u0443\u0433\u043E\u0439 \u043C\u0430\u043B\u044B\u0439 \u0431\u0438\u0437\u043D\u0435\u0441 \u0432 \u043D\u0430\u0448\u0435\u0439 \u0441\u0442\u0440\u0430\u043D\u0435\xBB,\u2009\u2013 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0414\u0435\u043D\u0438\u0441 \u0413\u0443\u0442\u043E\u0432. \u0421\u0435\u0433\u043E\u0434\u043D\u044F <a href="/workshop/catalog/klass-truda/">\xAB\u041A\u043B\u0430\u0441\u0441 \u0442\u0440\u0443\u0434\u0430\xBB</a> \u2013 \u044D\u0442\u043E \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0438\u0437 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0437\u0430\u043B\u043E\u0432: \u0434\u043B\u044F \u0448\u0443\u043C\u043D\u044B\u0445 \u0438 \u043D\u0435 \u043E\u0447\u0435\u043D\u044C \u0440\u0430\u0431\u043E\u0442, \u0434\u0435\u0442\u0441\u043A\u0438\u0439 \u0437\u0430\u043B \u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u0434\u043B\u044F \u043A\u043E\u043C\u0430\u043D\u0434. \u0412\xA0\u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u0440\u0430\u0441\u043F\u043E\u0440\u044F\u0436\u0435\u043D\u0438\u0438 \u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442\u043E\u0432 \u2013 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0430\u044F \u043F\u043E\u043A\u0440\u0430\u0441\u043E\u0447\u043D\u0430\u044F \u0438 \u043C\u0435\u0442\u0430\u043B\u043B\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0443\u0447\u0430\u0441\u0442\u043E\u043A. \u0412\xA0\u0434\u0432\u0443\u0445 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u0437\u0430\u043B\u0430\u0445 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u043E 20 \u043C\u0435\u0441\u0442, \u0430 \u0432 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0438, \u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u043E\u043C \u0434\u043B\u044F \u043A\u043E\u043C\u0430\u043D\u0434\u043D\u043E\u0439 \u0440\u0430\u0431\u043E\u0442\u044B,\u2009\u2013 15. \u0412\xA0\u043D\u0435\u0434\u0435\u043B\u044E \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u0438 \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u0432 \u043D\u0435\u043C \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B \u043F\u043E\u0441\u0435\u0449\u0430\u044E\u0442 \u043E\u043A\u043E\u043B\u043E 50\u201360 \u0447\u0435\u043B\u043E\u0432\u0435\u043A. \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043D\u0438\u0445\xA0\u2013 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0435 \u043A\u043B\u0438\u0435\u043D\u0442\u044B. \u041F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \xAB\u041A\u043B\u0430\u0441\u0441\u043E\u043C \u0442\u0440\u0443\u0434\u0430\xBB \u043C\u043E\u0436\u043D\u043E, \u043A\u0443\u043F\u0438\u0432 \u043C\u0435\u0441\u044F\u0447\u043D\u044B\u0439 \u0430\u0431\u043E\u043D\u0435\u043C\u0435\u043D\u0442 \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u044C\u044E 7000\xA0\u0440\u0443\u0431. \u0438\u043B\u0438 \u0431\u0438\u043B\u0435\u0442\u044B \u043D\u0430 30\xA0\u0447\u0430\u0441\u043E\u0432 (4000 \u0440\u0443\u0431.), \u043D\u0430 \u0434\u0435\u043D\u044C (1000 \u0440\u0443\u0431.) \u0438\u043B\u0438 \u043D\u0430 \u0447\u0430\u0441 (200 \u0440\u0443\u0431.).</p><p>\u041D\u0430 \u043E\u043F\u0435\u0440\u0430\u0442\u0438\u0432\u043D\u0443\u044E \u0441\u0430\u043C\u043E\u043E\u043A\u0443\u043F\u0430\u0435\u043C\u043E\u0441\u0442\u044C \xAB\u041A\u043B\u0430\u0441\u0441 \u0442\u0440\u0443\u0434\u0430\xBB \u0432\u044B\u0448\u0435\u043B \u043A \u043A\u043E\u043D\u0446\u0443 \u043F\u0435\u0440\u0432\u043E\u0433\u043E \u0433\u043E\u0434\u0430 \u0440\u0430\u0431\u043E\u0442\u044B. \u041F\u0440\u044F\u043C\u043E\u0439 \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0446\u0438\u0438 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u043D\u0435 \u043E\u0449\u0443\u0449\u0430\u0435\u0442. \xAB\u041D\u0430\u0448\u0438 \u0441\u043E\u043F\u0435\u0440\u043D\u0438\u043A\u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u043B\u0438 \u0441\u0438\u043B\u044C\u043D\u043E \u043F\u043E\u0437\u0436\u0435, \u0438 \u043E\u043D\u0438 \u043C\u0435\u043D\u0435\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B,\u2009\u2013 \u043F\u043E\u044F\u0441\u043D\u044F\u0435\u0442 \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C.\u2009\u2013 \u041E\u0434\u043D\u0430\u043A\u043E \u0435\u0441\u0442\u044C \u043C\u0430\u0441\u0441\u0430 \u043D\u0435\u043F\u0440\u044F\u043C\u044B\u0445 \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0442\u043E\u0432: \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u043B\u044E\u0434\u044F\u043C \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044E\u0442 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0448\u0438\u0440\u043E\u043A\u0438\u0439 \u0432\u044B\u0431\u043E\u0440, \u043D\u0430 \u043A\u0430\u043A\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0438 \u0440\u0430\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435 \u043F\u043E\u0442\u0440\u0430\u0442\u0438\u0442\u044C \u0434\u0435\u043D\u044C\u0433\u0438 \u0432 \u0431\u043E\u043B\u044C\u0448\u043E\u043C \u0433\u043E\u0440\u043E\u0434\u0435\xBB. \u041D\u0430\xA0\u043E\u0431\u043E\u0440\u043E\u0442 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430, \u0441\u0443\u043C\u043C\u0443 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0414\u0435\u043D\u0438\u0441 \u0413\u0443\u0442\u043E\u0432 \u043D\u0435 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442, \u0431\u043E\u043B\u044C\u0448\u0435 \u0432\u043B\u0438\u044F\u044E\u0442 \u0441\u0435\u0437\u043E\u043D\u043D\u044B\u0435 \u0444\u0430\u043A\u0442\u043E\u0440\u044B \u2013 \u043F\u0440\u0430\u0437\u0434\u043D\u0438\u043A\u0438, \u043F\u0435\u0440\u0438\u043E\u0434 \u043E\u0442\u043F\u0443\u0441\u043A\u043E\u0432 \u0438 \u0434\u0430\u0436\u0435\xA0\u043B\u0435\u0442\u043D\u044F\u044F \u043F\u043E\u0433\u043E\u0434\u0430. \xAB\u0412 \u043E\u0431\u043E\u0440\u043E\u0442\u0435 \u0432 \u0441\u0440\u0435\u0434\u043D\u0435\u043C 30\u201340% \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0434\u043E\u043B\u044F \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430, \u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0436\u0435 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043D\u0430 \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B,\u2009\u2013 \u043F\u043E\u044F\u0441\u043D\u044F\u0435\u0442 \u043E\u043D.\u2009\u2013 \u041E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u043E\u0445\u043E\u0434 \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 \u0437\u0430\u043A\u0430\u0437\u044B \u0438 \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u044F. \u0412\xA0\u0440\u0430\u0437\u043D\u044B\u0435 \u043C\u0435\u0441\u044F\u0446\u044B \u0446\u0438\u0444\u0440\u044B \u043C\u043E\u0433\u0443\u0442 \u0441\u0438\u043B\u044C\u043D\u043E \u043F\u043B\u0430\u0432\u0430\u0442\u044C: \u0432 \u0434\u0435\u043A\u0430\u0431\u0440\u0435 \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0434\u043E\u043B\u044F \u043C\u0435\u0440\u043E\u043F\u0440\u0438\u044F\u0442\u0438\u0439, \u043D\u043E \u0441\u043D\u0438\u0436\u0430\u0435\u0442\u0441\u044F \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u043E\u0432\xBB.</p><p>\u0412\u0441\u044E \u043F\u0440\u0438\u0431\u044B\u043B\u044C \u0441\u0435\u043C\u0435\u0439\u043D\u0430\u044F \u043F\u0430\u0440\u0430 \u0440\u0435\u0438\u043D\u0432\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u2013 \u0432\u0435\u0441\u043D\u043E\u0439 \u043F\u0440\u0438\u0434\u0435\u0442\u0441\u044F \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0442\u044C \u043F\u043B\u043E\u0449\u0430\u0434\u044C \u0434\u043E 500\xA0\u043A\u0432.\u2009\u043C. \u0421\u0435\u0439\u0447\u0430\u0441 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u0437\u0430\u0433\u0440\u0443\u0436\u0435\u043D \u043D\u0430 \u0432\u0441\u0435 100%. \u0423\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0431\u0430\u0437\u0430, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0447\u0430\u0441\u0442\u044C \u0434\u0435\u043D\u0435\u0433 \u0443\u0439\u0434\u0435\u0442 \u043D\u0430 \u043F\u043E\u043A\u0443\u043F\u043A\u0443 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F. \xAB\u0412\xA0\u043D\u0430\u0448\u0438\u0445 \u043F\u043B\u0430\u043D\u0430\u0445 \u2013 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u043A\u043E\u043C\u0430\u043D\u0434\u044B \u043B\u044E\u0434\u0435\u0439 \u043D\u0430 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0439 \u0437\u0430\u0440\u043F\u043B\u0430\u0442\u0435, \u0447\u0442\u043E\u0431\u044B \u043C\u044B \u043C\u043E\u0433\u043B\u0438 \u043E\u0442\u043E\u0439\u0442\u0438 \u043E\u0442 \u043E\u043F\u0435\u0440\u0430\u0442\u0438\u0432\u043D\u043E\u0439 \u0437\u0430\u043D\u044F\u0442\u043E\u0441\u0442\u0438 \u0438 \u0441\u0444\u043E\u043A\u0443\u0441\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u0438 \u0440\u043E\u0441\u0442\u0435 \u0431\u0438\u0437\u043D\u0435\u0441\u0430\xBB,\u2009\u2013 \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442 \u0414\u0435\u043D\u0438\u0441 \u0413\u0443\u0442\u043E\u0432. \u041E\u043D \u043F\u0440\u0435\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0442\u0435 \u0436\u0435 \u0446\u0435\u043B\u0438, \u0447\u0442\u043E \u043B\u044E\u0431\u043E\u0439 \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C,\u2009\u2013 \u0434\u043E\u0432\u0435\u0441\u0442\u0438 \u043C\u0430\u043B\u044B\u0439 \u0431\u0438\u0437\u043D\u0435\u0441 \u0434\u043E \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0438 \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0442\u044C \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E\u0434\u043E\u0432\u043E\u0439 \u043E\u0431\u043E\u0440\u043E\u0442 \u043C\u0438\u043D\u0438\u043C\u0443\u043C \u0432 \u0434\u0432\u0430 \u0440\u0430\u0437\u0430.</p><h2 id="\u0441\u0432\u043E\u0438\u043C\u0438-\u0440\u0443\u043A\u0430\u043C\u0438" tabindex="-1">\u0421\u0432\u043E\u0438\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438 <a class="header-anchor" href="#\u0441\u0432\u043E\u0438\u043C\u0438-\u0440\u0443\u043A\u0430\u043C\u0438" aria-hidden="true">#</a></h2><p>\xAB\u0412\u0441\u0435 \u043F\u0440\u043E\u0441\u0442\u043E. \u041B\u044E\u0431\u0438\u043C \u0434\u0435\u0440\u0435\u0432\u043E. \u041B\u044E\u0431\u0438\u043C \u0440\u0435\u043C\u0435\u0441\u043B\u043E\xBB \u2013 \u044D\u0442\u043E\u0442 \u0441\u043B\u043E\u0433\u0430\u043D \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442 \u043A\u0430\u0436\u0434\u043E\u0433\u043E, \u043A\u0442\u043E \u0437\u0430\u0445\u043E\u0434\u0438\u0442 \u043D\u0430 \u0441\u0430\u0439\u0442 \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 Crafts Station. \u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440 \u0425\u0440\u0438\u0441\u0442\u043E\u0444\u043E\u0440\u043E\u0432 \u0438 \u041B\u0435\u0439\u043B\u0430 \u041B\u0430\u0444\u0442\u0430 \u043F\u0440\u0438\u0434\u0443\u043C\u0430\u043B\u0438, \u043A\u0430\u043A \u0437\u0430\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u043D\u0430 \u043B\u044E\u0431\u0432\u0438 \u0443\u043C\u0435\u043B\u044C\u0446\u0435\u0432 \u043A \u0434\u0435\u0440\u0435\u0432\u0443. \u0412 2014 \u0433. \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u044B\u0439 \u0438\u043C\u0438 Crafts Station \u0441\u0442\u0430\u0440\u0442\u043E\u0432\u0430\u043B \u043A\u0430\u043A \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0437\u0430 300 \u0440\u0443\u0431. \u0432 \u0447\u0430\u0441 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u043B \u0432\u043E\u043F\u043B\u043E\u0442\u0438\u0442\u044C \u0432 \u0436\u0438\u0437\u043D\u044C \u043B\u044E\u0431\u043E\u0439 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0439 \u0437\u0430\u043C\u044B\u0441\u0435\u043B. \u0421\u0435\u0439\u0447\u0430\u0441 \u043F\u0440\u043E\u0435\u043A\u0442 \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043B \u0441\u0438\u043B\u044B \u043D\u0430 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u041F\u0440\u0438\u0447\u0438\u043D\u044B \u043F\u0435\u0440\u0435\u043E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u0438 \u043D\u043E\u0441\u044F\u0442 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0439 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440 \u2013 \u0432\xA0\u043F\u0440\u043E\u0448\u043B\u043E\u043C \u0433\u043E\u0434\u0443 \u043E\u0431\u043E\u0440\u043E\u0442 Crafts Station \u0441\u043E\u0441\u0442\u0430\u0432\u0438\u043B \u043F\u043E\u0440\u044F\u0434\u043A\u0430 1 \u043C\u043B\u043D \u0440\u0443\u0431\u043B\u0435\u0439. \u0418\u0437\xA0\u043D\u0438\u0445 10% \u043F\u0440\u0438\u0448\u043B\u043E\u0441\u044C \u043D\u0430 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433, \u0430 90% \u2013 \u043D\u0430 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0439 \u0446\u0435\u0445.</p><p>\u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440 \u0425\u0440\u0438\u0441\u0442\u043E\u0444\u043E\u0440\u043E\u0432 \u0438 \u041B\u0435\u0439\u043B\u0430 \u041B\u0430\u0444\u0442\u0430 \u043E\u0431\u0430 \u0432\u044B\u0440\u043E\u0441\u043B\u0438 \u0432 \u0422\u0432\u0435\u0440\u0438. \u041E\u043D\u0438 \u043F\u043E\u0437\u043D\u0430\u043A\u043E\u043C\u0438\u043B\u0438\u0441\u044C \u0435\u0449\u0435 \u043F\u043E\u0434\u0440\u043E\u0441\u0442\u043A\u0430\u043C\u0438, \u043F\u043E\u0442\u043E\u043C \u0434\u043E\u043B\u0433\u043E \u043D\u0435 \u0432\u0438\u0434\u0435\u043B\u0438\u0441\u044C, \u0430 \u0432\u0441\u0442\u0440\u0435\u0442\u0438\u043B\u0438\u0441\u044C \u0443\u0436\u0435 \u043F\u043E\u0441\u043B\u0435 \u043F\u0435\u0440\u0435\u0435\u0437\u0434\u0430 \u0432 \u041C\u043E\u0441\u043A\u0432\u0443. \u0414\u043E\xA0Crafts Station \u041B\u0435\u0439\u043B\u0430, \u043F\u043E \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u044E \u043C\u0430\u0440\u043A\u0435\u0442\u043E\u043B\u043E\u0433 \u0438 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A \u0432 \u0441\u0444\u0435\u0440\u0435 \u043F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0445 \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u0439, \u0440\u0430\u0431\u043E\u0442\u0430\u043B\u0430 \u043D\u0430 \u0438\u043D\u0442\u0435\u0440\u044C\u0435\u0440\u043D\u043E\u043C \u0440\u044B\u043D\u043A\u0435 \u0432 \u043E\u0442\u0434\u0435\u043B\u0435 \u043F\u0440\u043E\u0434\u0430\u0436. \u041D\u0435\u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E, \u0447\u0442\u043E \u043E\u043D\u0430 \u0445\u043E\u0440\u043E\u0448\u043E \u0443\u043C\u0435\u0435\u0442 \u0443\u0431\u0435\u0436\u0434\u0430\u0442\u044C \u043B\u044E\u0434\u0435\u0439. \u0412 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u044B \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E\u0433\u043E \u0438\u0445 \u0441 \u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440\u043E\u043C \u0441\u0442\u0430\u0440\u0442\u0430\u043F\u0430 \u041B\u0435\u0439\u043B\u0430 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u043B\u0430 \u043F\u043E\u0432\u0435\u0440\u0438\u0442\u044C \u043D\u0435 \u043E\u0434\u043D\u043E\u0433\u043E \u043F\u043E\u0441\u0442\u0430\u0432\u0449\u0438\u043A\u0430 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0434\u0440\u0435\u0432\u0435\u0441\u0438\u043D\u044B. \u0412\xA0\u0422\u0432\u0435\u0440\u0438 \u0425\u0440\u0438\u0441\u0442\u043E\u0444\u043E\u0440\u043E\u0432 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u043B \u0434\u0432\u0443\u043C\u044F \u043A\u043B\u0443\u0431\u0430\u043C\u0438, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u043F\u043E\u0441\u043B\u0435 \u043F\u0435\u0440\u0435\u0435\u0437\u0434\u0430 \u0432\xA0\u041C\u043E\u0441\u043A\u0432\u0443 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u043B \u0430\u0442\u0430\u043A\u043E\u0432\u0430\u0442\u044C event-\u0440\u044B\u043D\u043E\u043A. \u0414\u0432\u0430 \u0433\u043E\u0434\u0430 \u043D\u0430\u0437\u0430\u0434 \u041B\u0435\u0439\u043B\u0430\xA0\u0432\u0435\u0440\u043D\u0443\u043B\u0430\u0441\u044C \u0441 \u041C\u0438\u043B\u0430\u043D\u0441\u043A\u043E\u0439 \u0432\u044B\u0441\u0442\u0430\u0432\u043A\u0438\xA0\u043C\u0435\u0431\u0435\u043B\u0438 \u0441 \u0438\u0434\u0435\u0435\u0439 \u0441\u0442\u0430\u0442\u044C \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u0435\u043B\u0435\u043C \u0432 \u0420\u043E\u0441\u0441\u0438\u0438 \u043E\u0434\u043D\u043E\u0439\xA0\u0441\u043B\u043E\u0432\u0435\u043D\u0441\u043A\u043E\u0439 \u0444\u0430\u0431\u0440\u0438\u043A\u0438. \xAB\u041C\u044B \u0443\u0434\u0430\u0440\u0438\u043B\u0438\u0441\u044C \u0432 \u043F\u043E\u0438\u0441\u043A\u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0433\u043E\u0442\u043E\u0432\u043E\u0439 \u043F\u0440\u043E\u0434\u0443\u043A\u0446\u0438\u0438 \u043D\u0430 \u0440\u043E\u0441\u0441\u0438\u0439\u0441\u043A\u043E\u043C \u0440\u044B\u043D\u043A\u0435. \u042D\u0442\u043E \u0431\u044B\u043B 2014 \u0433., \u043A\u043E\u0433\u0434\u0430 \u0435\u0432\u0440\u043E \u043D\u0430\u0447\u0430\u043B\u043E \u043B\u0438\u0445\u043E\u0440\u0430\u0434\u0438\u0442\u044C, \u0437\u0430\u043D\u044F\u0442\u044B\u0435 \u043D\u0430 \u043E\u0444\u0438\u0441, \u043E\u0431\u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E \u0438 \u0436\u0438\u0437\u043D\u044C \u0434\u0435\u043D\u044C\u0433\u0438 \u0431\u044B\u0441\u0442\u0440\u043E\xA0\u0437\u0430\u043A\u043E\u043D\u0447\u0438\u043B\u0438\u0441\u044C, \u0430 \u043E\u0442\u0434\u0430\u0447\u0438 \u043C\u044B \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u043B\u0438, \u0438 \u043D\u0443\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0441\u0440\u043E\u0447\u043D\u043E \u0447\u0442\u043E-\u0442\u043E \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C\xBB,\u2009\u2013 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E\u043D\u0430.</p><p>\u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440 \u0434\u0430\u0432\u043D\u043E \u0443\u0432\u043B\u0435\u043A\u0430\u043B\u0441\u044F \u043F\u0435\u0440\u0435\u0434\u0435\u043B\u043A\u043E\u0439 \u043C\u0435\u0431\u0435\u043B\u0438. \u0412 \u044D\u0442\u043E\u0442 \u0442\u044F\u0436\u0435\u043B\u044B\u0439 \u0434\u043B\u044F \u0441\u0435\u043C\u044C\u0438 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0439 \u043F\u0435\u0440\u0438\u043E\u0434 \u043E\u043D \u0437\u0430\u0434\u0443\u043C\u0430\u043B \u0441\u043E\u0431\u0440\u0430\u0442\u044C \u043F\u043E \u041C\u043E\u0441\u043A\u0432\u0435 \u043D\u0438\u043A\u043E\u043C\u0443 \u043D\u0435 \u043D\u0443\u0436\u043D\u0443\u044E \u0441\u043E\u0432\u0435\u0442\u0441\u043A\u0443\u044E \u043C\u0435\u0431\u0435\u043B\u044C \u0438 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0438\u0437 \u043D\u0435\u0435 \u043D\u0435\u0447\u0442\u043E \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0435. \xAB\u0414\u0430\u0442\u044C \u0432\u0442\u043E\u0440\u0443\u044E \u0436\u0438\u0437\u043D\u044C\xBB,\u2009\u2013 \u0443\u0442\u043E\u0447\u043D\u044F\u0435\u0442 \u041B\u0435\u0439\u043B\u0430. \u0412 \u043A\u043E\u043D\u0446\u0435 2014 \u0433., \u0447\u0442\u043E\u0431\u044B \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0442\u044C \u0437\u0430\u0434\u0443\u043C\u043A\u0443, \u0441\u0435\u043C\u0435\u0439\u043D\u0430\u044F \u043F\u0430\u0440\u0430 \u0441\u043D\u043E\u0432\u0430 \u0437\u0430\u043D\u044F\u043B\u0430 \u0434\u0435\u043D\u044C\u0433\u0438 \u0443 \u0440\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u043A\u043E\u0432 \u0438 \u0430\u0440\u0435\u043D\u0434\u043E\u0432\u0430\u043B\u0430 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u043D\u0430 \u041F\u0440\u0435\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u043A\u0435. \u0422\u043E\u0433\u0434\u0430 \u0436\u0435 \u0440\u043E\u0434\u0438\u043B\u0430\u0441\u044C \u0438\u0434\u0435\u044F Crafts Station. \xAB\u041C\u044B \u0440\u0435\u0448\u0438\u043B\u0438 \u0432 \u0442\u0430\u043A\u0438\u0435 \u043D\u0435\u043F\u0440\u043E\u0441\u0442\u044B\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u0430, \u043A\u043E\u0433\u0434\u0430 \u0441\u043E \u0432\u0441\u0435\u0445 \u0441\u0442\u043E\u0440\u043E\u043D \u043A\u0440\u0438\u0447\u0430\u0442 \u043E \u043A\u0440\u0438\u0437\u0438\u0441\u0435, \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0438\u0442\u044C \u044D\u043D\u0442\u0443\u0437\u0438\u0430\u0441\u0442\u0430\u043C-\u0443\u043C\u0435\u043B\u044C\u0446\u0430\u043C \u0437\u0430 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0435 \u0434\u0435\u043D\u044C\u0433\u0438 \u0430\u0440\u0435\u043D\u0434\u043E\u0432\u0430\u0442\u044C \u0443\u0433\u043E\u043B \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442, \u0447\u0442\u043E\u0431\u044B \u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C \u0447\u0442\u043E-\u0442\u043E \u0434\u043B\u044F \u0441\u0435\u0431\u044F, \u0430 \u043B\u0443\u0447\u0448\u0435\xA0\u2013 \u043D\u0430\u0447\u0430\u0442\u044C \u0441\u0432\u043E\u0435 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0435 \u0434\u0435\u043B\u043E\xBB,\u2009\u2013 \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u0441\u0443\u043F\u0440\u0443\u0433\u0438. \u0412 \u0434\u0430\u043B\u044C\u043D\u0435\u0439\u0448\u0435\u043C \u043E\u043D\u0438 \u043F\u043E\u043D\u044F\u043B\u0438, \u0447\u0442\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u043B\u044E\u0431\u0438\u0442\u0435\u043B\u0435\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0432\u0435\u0441\u044C \u0434\u0438\u0430\u043F\u0430\u0437\u043E\u043D \u2013 \u043E\u0442 \u0440\u0435\u0437\u044C\u0431\u044B \u043F\u043E \u0434\u0435\u0440\u0435\u0432\u0443 \u0434\u043E \u0438\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u0448\u043A\u0430\u0444\u0430 \u2013 \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 \u0440\u043E\u0441\u0442 \u043E\u0442\u0440\u0430\u0441\u043B\u0438 \u0437\u0434\u043E\u0440\u043E\u0432\u043E\u0439 \u0435\u0434\u044B, \u0438 \u044D\u0442\u043E\u0442 \u0440\u044B\u043D\u043E\u0447\u043D\u044B\u0439 \u0441\u0434\u0432\u0438\u0433 \u043C\u043E\u0436\u043D\u043E \u0432\u044B\u0433\u043E\u0434\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C.</p><p>\u0421\u0442\u0430\u0440\u0442\u043E\u0432\u044B\u0439 \u043A\u0430\u043F\u0438\u0442\u0430\u043B \u0443 \u041B\u0435\u0439\u043B\u044B \u0438 \u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440\u0430 \u0431\u044B\u043B \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u2013 \u0432\u0441\u0435\u0433\u043E 300\u2009000 \u0440\u0443\u0431. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u0443\u0448\u043B\u0438 \u043D\u0430 \u0430\u0440\u0435\u043D\u0434\u0443 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u043F\u043B\u0430\u0442\u0435\u0436\u043E\u043C, \u043F\u043E\u043A\u0443\u043F\u043A\u0443 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u0440\u0430\u0441\u0445\u043E\u0434\u043D\u0438\u043A\u043E\u0432 \u043F\u043E \u0434\u0435\u0440\u0435\u0432\u043E\u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0435. \u041C\u0435\u0431\u0435\u043B\u044C \u0441\u043A\u0443\u043F\u0438\u043B\u0438 \u0437\u0430 \u0431\u0435\u0441\u0446\u0435\u043D\u043E\u043A \u043D\u0430 Avito. \u041F\u043E\u0441\u043B\u0435 \u0441\u0442\u0430\u0440\u0442\u0430 \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044F\u043C \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u043B\u043E \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432 \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432. \u0427\u0442\u043E\u0431\u044B \u043E\u0442\u043A\u0440\u044B\u0442\u044C \u0440\u0435\u043C\u0435\u0441\u043B\u0435\u043D\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433, \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043E\u0434\u043D\u0438\u0445 \u0434\u0435\u043D\u0435\u0433, \u0441\u0447\u0438\u0442\u0430\u0435\u0442 \u041B\u0435\u0439\u043B\u0430 \u041B\u0430\u0444\u0442\u0430. \u041D\u0443\u0436\u043D\u043E \u0443\u043C\u0435\u0442\u044C \u043E\u0431\u0440\u0430\u0449\u0430\u0442\u044C\u0441\u044F \u0441\u043E \u0441\u0442\u0430\u043D\u043A\u0430\u043C\u0438, \u043F\u0440\u0438 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u2013 \u0440\u0430\u0437\u043E\u0431\u0440\u0430\u0442\u044C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435, \u043F\u043E\u0447\u0438\u043D\u0438\u0442\u044C \u0438 \u0441\u043D\u043E\u0432\u0430 \u0441\u043E\u0431\u0440\u0430\u0442\u044C. \xAB\u0412\u0430\u0436\u043D\u043E \u0432\u044B\u0431\u0440\u0430\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u0445 \u043F\u043E\u0441\u0442\u0430\u0432\u0449\u0438\u043A\u043E\u0432 \u0438 \u0440\u0430\u0437\u0431\u0438\u0440\u0430\u0442\u044C\u0441\u044F \u0432 \u0432\u0438\u0434\u0430\u0445 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432, \u0437\u043D\u0430\u0442\u044C \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u044E \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0430 \u0442\u043E\u0433\u043E \u0438\u043B\u0438 \u0438\u043D\u043E\u0433\u043E \u0438\u0437\u0434\u0435\u043B\u0438\u044F,\u2009\u2013 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E\u043D\u0430.\u2009\u2013 \u041D\u0443\u0436\u043D\u043E \u043B\u044E\u0431\u0438\u0442\u044C \u0438 \u0438\u0437\u0443\u0447\u0430\u0442\u044C \u0434\u0438\u0437\u0430\u0439\u043D, \u0437\u043D\u0430\u0442\u044C, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u043D\u0435\u0442\u0432\u043E\u0440\u043A\u0438\u043D\u0433, \u0438 \u0443\u043C\u0435\u043B\u043E \u0438\u043C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F\xBB.</p><p>\u041F\u043E\u043B\u0435\u0437\u043D\u044B\u0435 \u0437\u043D\u0430\u043A\u043E\u043C\u0441\u0442\u0432\u0430 \u043F\u043E\u043C\u043E\u0433\u043B\u0438 Crafts Station \u0440\u0435\u0448\u0438\u0442\u044C \u0433\u043B\u0430\u0432\u043D\u044B\u0439 \u0432\u043E\u043F\u0440\u043E\u0441 \u0441 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435\u043C. \u041F\u043E\u0447\u0442\u0438 \u0441\u0440\u0430\u0437\u0443 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u043F\u0443\u0441\u043A\u0430 \u043D\u0430 \u043D\u0438\u0445 \u0432\u044B\u0448\u0435\u043B \u0432\u043B\u0430\u0434\u0435\u043B\u0435\u0446 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0414\u043C\u0438\u0442\u0440\u0438\u0439 \u0412\u043E\u043B\u043A\u043E\u0432. \u0423 \u043D\u0435\u0433\u043E \u0435\u0441\u0442\u044C \u0441\u0442\u0430\u043D\u043A\u0438, \u0430 \u0443 \u0425\u0440\u0438\u0441\u0442\u043E\u0444\u043E\u0440\u043E\u0432\u0430 \u0441 \u041B\u0430\u0444\u0442\u043E\u0439\xA0\u2013 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435. \u041F\u043E\u0447\u0435\u043C\u0443 \u0431\u044B \u043D\u0435 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0438\u0442\u044C \u0443\u0441\u0438\u043B\u0438\u044F? \u0422\u0430\u043A, \u0432 \u043F\u0435\u0440\u0435\u0447\u043D\u0435 \u0443\u0441\u043B\u0443\u0433 Crafts Station \u043F\u043E\u044F\u0432\u0438\u043B\u0438\u0441\u044C \u043F\u0435\u0440\u0432\u044B\u0435 \u043C\u0430\u0441\u0442\u0435\u0440-\u043A\u043B\u0430\u0441\u0441\u044B \u0438 \u043A\u043E\u0432\u043E\u0440\u043A\u0435\u0440\u044B \u043D\u0430 \u0440\u0430\u0437\u043E\u0432\u043E\u0439 \u043E\u0441\u043D\u043E\u0432\u0435 (300\xA0\u0440\u0443\u0431. \u0432 \u0447\u0430\u0441). \u0422\u043E\u0433\u0434\u0430 \u0436\u0435 \u0432 \u043F\u0440\u043E\u0435\u043A\u0442 \u043F\u0440\u0438\u0448\u0435\u043B \u0441\u0442\u0430\u0440\u0448\u0438\u0439 \u0431\u0440\u0430\u0442 \u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440\u0430 \u0410\u043D\u0434\u0440\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0449\u0435 \u0434\u043E \u043F\u0435\u0440\u0435\u0435\u0437\u0434\u0430 \u0432\xA0\u041C\u043E\u0441\u043A\u0432\u0443 \u0441\u0442\u0440\u043E\u0438\u043B \u0434\u043E\u043C\u0430. \u041F\u0440\u043E\u0448\u043B\u043E\u0439 \u0432\u0435\u0441\u043D\u043E\u0439 \u043F\u0440\u043E\u0435\u043A\u0442 \u043F\u0435\u0440\u0435\u0435\u0445\u0430\u043B \u0432 \u0431\u043E\u043B\u0435\u0435 \u0443\u0434\u043E\u0431\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E\xA0\u2013 \u043D\u0430 \u0437\u0430\u0432\u043E\u0434 \xAB\u041A\u0440\u0438\u0441\u0442\u0430\u043B\u043B\xBB. \u041D\u0430\xA0\u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u043F\u043E\u043B\u0443\u0433\u043E\u0434\u0430 Crafts Station \u0441\u043E\u0432\u043C\u0435\u0449\u0430\u043B\u0430 \u0434\u0432\u0430 \u0444\u043E\u0440\u043C\u0430\u0442\u0430 \u2013 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439\xA0\u0438\xA0\u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430. \u0420\u0435\u0437\u0438\u0434\u0435\u043D\u0442\u044B \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u043B\u0438 \u0441 \u0440\u0430\u0437\u043D\u044B\u043C\u0438 \u0446\u0435\u043B\u044F\u043C\u0438 \u2013 \xAB\u043A\u0442\u043E \u0445\u043E\u0442\u0435\u043B \u0447\u0442\u043E-\u0442\u043E \u043F\u043E\u0447\u0438\u043D\u0438\u0442\u044C, \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u043F\u043E\u043B\u043E\u0447\u043A\u0443 \u0438\u043B\u0438 \u0430\u0440\u0442-\u043E\u0431\u044A\u0435\u043A\u0442 \u0438\u0437 \u0432\u0435\u0442\u043E\u0447\u0435\u043A \u0431\u0435\u0440\u0435\u0437\u044B\xBB. \u041F\u0440\u043E\u043F\u0443\u0441\u043A\u043D\u0430\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430 \u0431\u044B\u043B\u0430 \u043D\u0435 \u0441\u0442\u043E\u043B\u044C \u0432\u044B\u0441\u043E\u043A\u043E\u0439, \u043A\u0430\u043A \u0445\u043E\u0442\u0435\u043B\u043E\u0441\u044C,\u2009\u2013 \u0434\u043E\xA0\u043F\u044F\u0442\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0432 \u0434\u0435\u043D\u044C. \u041A\u043E\u0433\u0434\u0430\xA0\u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0445 \u0437\u0430\u043A\u0430\u0437\u043E\u0432\xA0\u0443\u0432\u0435\u043B\u0438\u0447\u0438\u043B\u043E\u0441\u044C, \u043F\u0435\u0440\u0435\u0434 \u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u044F\u043C\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u0432\u0441\u0442\u0430\u043B \u0432\u043E\u043F\u0440\u043E\u0441, \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \xAB\u0440\u0430\u0441\u043F\u044B\u043B\u044F\u0442\u044C\u0441\u044F\xBB \u0438\u043B\u0438 \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.</p><p>\xAB\u041C\u044B \u043A\u043E\u043D\u0435\u0447\u043D\u043E \u0436\u0435 \u0432\u044B\u0431\u0440\u0430\u043B\u0438 \u0432\u0442\u043E\u0440\u043E\u0435. \u041D\u0430\u0441 \u043F\u0435\u0440\u0435\u0441\u0442\u0430\u043B \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u044F\u0442\u044C \u0442\u043E\u0442 \u0441\u0435\u0440\u0432\u0438\u0441, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043C\u044B \u043C\u043E\u0433\u043B\u0438 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0438\u0442\u044C \u043A\u043E\u0432\u043E\u0440\u043A\u0435\u0440\u0430\u043C\xBB,\u2009\u2013 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u041B\u0435\u0439\u043B\u0430 \u041B\u0430\u0444\u0442\u0430. \u0418\u0434\u0435\u044E \u0441\u0434\u0430\u0447\u0438 \u0432 \u0430\u0440\u0435\u043D\u0434\u0443 \u0440\u0430\u0431\u043E\u0447\u0438\u0445 \u043C\u0435\u0441\u0442 \u0435\u0434\u0438\u043D\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0440\u0435\u0448\u0438\u043B\u0438 \u043E\u0442\u043B\u043E\u0436\u0438\u0442\u044C \u0434\u043E \u043B\u0443\u0447\u0448\u0438\u0445 \u0432\u0440\u0435\u043C\u0435\u043D. \u0421\u0435\u0439\u0447\u0430\u0441 <a href="/workshop/tour/crafts-station/">Crafts Station</a> \u2013 \u044D\u0442\u043E \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0439 \u0446\u0435\u0445 \u0438 \u043A\u043E\u043C\u0430\u043D\u0434\u0430 \u0438\u0437 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432 \u0438 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u043F\u043E\u0434\u043C\u0430\u0441\u0442\u0435\u0440\u044C\u0435\u0432. \u0412 \u043F\u0440\u043E\u0448\u043B\u043E\u043C \u0433\u043E\u0434\u0443 \u043E\u0431\u043E\u0440\u043E\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0441\u043E\u0441\u0442\u0430\u0432\u0438\u043B \u043F\u043E\u0440\u044F\u0434\u043A\u0430 1\xA0\u043C\u043B\u043D \u0440\u0443\u0431. \u0412 2016\u2011\u043C \u0412\u043B\u0430\u0434\u0438\u043C\u0438\u0440 \u0438 \u041B\u0435\u0439\u043B\u0430 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u044B \u0435\u0433\u043E \u0443\u0434\u0432\u043E\u0438\u0442\u044C. \u041F\u043B\u0430\u043D\u043E\u0432 \u0443 \u043D\u0438\u0445 \u0433\u0440\u043E\u043C\u0430\u0434\u044C\u0435 \u2013 \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0442\u044C \u043F\u043B\u043E\u0449\u0430\u0434\u044C \u0437\u0430 \u0441\u0447\u0435\u0442 \u043E\u043F\u0442\u0438\u043C\u0438\u0437\u0430\u0446\u0438\u0438 \u0440\u0430\u0437\u043C\u0435\u0449\u0435\u043D\u0438\u044F \u0441\u0442\u0430\u043D\u043A\u043E\u0432, \u0434\u043E\u043A\u0443\u043F\u0438\u0442\u044C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435, \u043D\u0430\u043B\u0430\u0434\u0438\u0442\u044C \u0434\u0435\u043B\u043E\u0432\u044B\u0435 \u0441\u0432\u044F\u0437\u0438 \u0441 \u043D\u043E\u0432\u044B\u043C\u0438 \u043F\u043E\u0441\u0442\u0430\u0432\u0449\u0438\u043A\u0430\u043C\u0438\u2026 \xABCrafts Station\xA0\u2013 \u044D\u0442\u043E \u043D\u0430\u0448\u0435 \u0441\u0435\u043C\u0435\u0439\u043D\u043E\u0435 \u0434\u0438\u0442\u044F, \u0441\u0442\u0440\u0430\u0441\u0442\u044C \u0438 \u043B\u044E\u0431\u043E\u0432\u044C \u043D\u0430 \u0432\u0441\u044E \u0436\u0438\u0437\u043D\u044C,\u2009\u2013 \u043F\u0440\u0438\u0437\u043D\u0430\u0435\u0442\u0441\u044F \u041B\u0435\u0439\u043B\u0430 \u041B\u0430\u0444\u0442\u0430.\u2009\u2013 \u041A\u043E\u043C\u0430\u043D\u0434\u0430 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u0434\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0443, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043D\u0435 \u043B\u044E\u0431\u0438\u0442\u044C \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u043E\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u0434\u0435\u0440\u0435\u0432\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432 \u0442\u0432\u043E\u0438\u0445 \u0440\u0443\u043A\u0430\u0445 \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 \u0443\u0434\u043E\u0431\u043D\u044B\u0439 \u043F\u0440\u0435\u0434\u043C\u0435\u0442 \u0438\u043D\u0442\u0435\u0440\u044C\u0435\u0440\u0430, \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\xBB.</p><h2 id="\u0440\u0430\u0434\u043E\u0441\u0442\u044C-\u0442\u0440\u0443\u0434\u0430" tabindex="-1">\u0420\u0430\u0434\u043E\u0441\u0442\u044C \u0442\u0440\u0443\u0434\u0430 <a class="header-anchor" href="#\u0440\u0430\u0434\u043E\u0441\u0442\u044C-\u0442\u0440\u0443\u0434\u0430" aria-hidden="true">#</a></h2><p>\u041E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043E\u043D \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043D\u0435 \u0441\u0432\u043E\u0438\u043C \u0434\u0435\u043B\u043E\u043C, \u043F\u0440\u0438\u0448\u043B\u043E \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D\u0443 \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432\u0443 \u0432 30 \u043B\u0435\u0442. \u0412\u044B\u043F\u043E\u043B\u043D\u044F\u044F \u043E\u0447\u0435\u0440\u0435\u0434\u043D\u043E\u0439 \u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u0441\u043A\u0438\u0439 \u0437\u0430\u043A\u0430\u0437 \u0434\u043B\u044F \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u043E\u0433\u043E \u0430\u0433\u0435\u043D\u0442\u0441\u0442\u0432\u0430 Saatchi &amp; Saatchi, \u043E\u043D \u043F\u043E\u043D\u044F\u043B, \u0447\u0442\u043E \u043F\u0440\u043E\u0441\u0438\u0436\u0438\u0432\u0430\u0435\u0442 \u0436\u0438\u0437\u043D\u044C \u043F\u0435\u0440\u0435\u0434 \u043A\u043E\u043C\u043F\u044C\u044E\u0442\u0435\u0440\u043E\u043C. \u041D\u0435\u043E\u0436\u0438\u0434\u0430\u043D\u043D\u043E \u0435\u043C\u0443 \u0437\u0430\u0445\u043E\u0442\u0435\u043B\u043E\u0441\u044C \u043F\u043E\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0433\u043E\u043B\u043E\u0432\u043E\u0439, \u043D\u043E \u0438 \u0440\u0443\u043A\u0430\u043C\u0438. \u0412 2007 \u0433. \u043E\u0442 \u043C\u044B\u0441\u043B\u0435\u0439 \u043E\u043D \u043F\u0435\u0440\u0435\u0448\u0435\u043B \u043A \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C \u2013 \u0443\u0432\u043E\u043B\u0438\u043B\u0441\u044F \u0438\u0437 \u043F\u0440\u0435\u0441\u0442\u0438\u0436\u043D\u043E\u0433\u043E \u0430\u0433\u0435\u043D\u0442\u0441\u0442\u0432\u0430, \u043F\u0435\u0440\u0435\u0435\u0445\u0430\u043B \u0432 \u041F\u0438\u0442\u0435\u0440 \u0438 \u0443\u0441\u0442\u0440\u043E\u0438\u043B\u0441\u044F \u0440\u0430\u0437\u043D\u043E\u0440\u0430\u0431\u043E\u0447\u0438\u043C \u043D\u0430 \u0441\u0442\u0440\u043E\u0439\u043A\u0443. \u041D\u0430 \u044D\u0442\u043E\u0439 \u043F\u043E\u0437\u0438\u0446\u0438\u0438 \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432 \u0434\u043E\u043B\u0433\u043E \u043D\u0435 \u043F\u0440\u043E\u0434\u0435\u0440\u0436\u0430\u043B\u0441\u044F \u2013 \u0431\u044B\u0441\u0442\u0440\u043E \u043F\u043E\u0432\u044B\u0441\u0438\u043B\u0438 \u0434\u043E \u043F\u0440\u043E\u0440\u0430\u0431\u0430. \u0412\u043E \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u043D\u0430 \u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u043E\u043D \u0432\u0441\u0435\u0440\u044C\u0435\u0437 \u0443\u0432\u043B\u0435\u043A\u0441\u044F \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u043C \u0434\u0435\u043B\u043E\u043C. \u0421\u0432\u043E\u0438 \u0438\u0437\u0434\u0435\u043B\u0438\u044F \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u043D\u0430\u0447\u0430\u043B \u0441\u0434\u0430\u0432\u0430\u0442\u044C \u0432 \u043C\u0430\u0433\u0430\u0437\u0438\u043D \u044D\u043A\u0441\u043A\u043B\u044E\u0437\u0438\u0432\u043D\u044B\u0445 \u043F\u043E\u0434\u0430\u0440\u043A\u043E\u0432 \xAB\u0411\u044E\u0440\u043E \u043D\u0430\u0445\u043E\u0434\u043E\u043A\xBB. \u042D\u0442\u043E \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043D\u0430\u0442\u043E\u043B\u043A\u043D\u0443\u043B\u043E \u0435\u0433\u043E \u043D\u0430 \u0438\u0434\u0435\u044E \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u043C\u0435\u0441\u0442\u043E, \u0433\u0434\u0435 \u043B\u044E\u0431\u043E\u0439 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u043C\u043E\u0433 \u0431\u044B \u0437\u0430 \u043F\u043E\u0447\u0430\u0441\u043E\u0432\u0443\u044E \u043F\u043B\u0430\u0442\u0443 \u043F\u043E\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0441 \u0434\u0435\u0440\u0435\u0432\u043E\u043C \u0438\u043B\u0438 \u0434\u0440\u0443\u0433\u0438\u043C \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u043C.</p><p>\u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0432\u044B\u043D\u0430\u0448\u0438\u0432\u0430\u043B \u0438\u0434\u0435\u044E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0435\u0449\u0435 \u0434\u043E\u043B\u044C\u0448\u0435, \u0435\u0441\u043B\u0438 \u0431\u044B \u0432 2012\xA0\u0433. \u043D\u0435 \u043F\u043E\u0434\u0435\u043B\u0438\u043B\u0441\u044F \u0435\u044E \u0441 \u0441\u043E\u043A\u0443\u0440\u0441\u043D\u0438\u043A\u043E\u043C \u043F\u043E \u0423\u0440\u0430\u043B\u044C\u0441\u043A\u043E\u043C\u0443 \u0433\u043E\u0441\u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0443 \u0438 \u0432\u043B\u0430\u0434\u0435\u043B\u044C\u0446\u0435\u043C \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u043E\u0439 BTL-\u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0438 \xAB\u041A\u043E\u043D\u0442\u0438\u043D\u0435\u043D\u0442 \u041F\u043E\u0441\u0442\xBB \u041E\u043B\u0435\u0433\u043E\u043C \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432\u044B\u043C. \u041A \u0442\u043E\u043C\u0443 \u043C\u043E\u043C\u0435\u043D\u0442\u0443 \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432 \u0432\u0435\u0440\u043D\u0443\u043B\u0441\u044F \u0432 \u041C\u043E\u0441\u043A\u0432\u0443, \u043D\u0430\u0439\u0434\u044F \u0440\u0430\u0431\u043E\u0442\u0443 \u043D\u0430 \u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u0432 \u041D\u0430\u0445\u0430\u0431\u0438\u043D\u043E. \u0412\xA0\u043F\u0440\u043E\u0435\u043A\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \xAB\u0414\u0432\u043E\u0440 \u0421\u043E\u0442\u0440\u0443\u0434\u043D\u0435\u0439\xBB \u043F\u0440\u0438\u044F\u0442\u0435\u043B\u0438 \u0432\u043B\u043E\u0436\u0438\u043B\u0438 \u043B\u0438\u0447\u043D\u044B\u0435 \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u044F \u2013 \u043E\u043A\u043E\u043B\u043E 500\u2009000 \u0440\u0443\u0431. \u041F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u0441\u0443\u043C\u043C\u044B \u0443\u0448\u043B\u0430 \u043D\u0430 \u043F\u043E\u043A\u0443\u043F\u043A\u0443 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0435 \u2013 \u043D\u0430 \u0430\u0440\u0435\u043D\u0434\u0443 \u043A\u043E\u043C\u043D\u0430\u0442\u044B \u043F\u043B\u043E\u0449\u0430\u0434\u044C\u044E 30 \u043A\u0432. \u043C \u0432 \u043F\u043E\u0434\u0432\u0430\u043B\u0435 \u043E\u0434\u043D\u043E\u0433\u043E \u0438\u0437 \u0434\u043E\u043C\u043E\u0432 \u0432 \u041C\u0438\u043B\u044E\u0442\u0438\u043D\u0441\u043A\u043E\u043C \u043F\u0435\u0440\u0435\u0443\u043B\u043A\u0435. \u0421 \u043C\u0435\u0441\u0442\u043E\u043C \u0441\u0442\u0430\u0440\u0442\u0430\u043F\u0435\u0440\u0430\u043C \u043F\u043E\u0432\u0435\u0437\u043B\u043E \u2013 \u0434\u043E \u043D\u0438\u0445 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u0441\u043D\u0438\u043C\u0430\u043B\u0430 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0438 \u043F\u0435\u0440\u0435\u0435\u0437\u0434\u0435 \u043E\u0441\u0442\u0430\u0432\u0438\u043B\u0430 \u043F\u043E\u0441\u043B\u0435 \u0441\u0435\u0431\u044F \u0447\u0430\u0441\u0442\u044C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F. \u0427\u0435\u0440\u0435\u0437 \u0442\u0440\u0438 \u043C\u0435\u0441\u044F\u0446\u0430 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u043F\u0443\u0441\u043A\u0430, \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0435\u043A\u0442 \u0432\u044B\u0448\u0435\u043B \u043D\u0430 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0439 \u043D\u043E\u043B\u044C, \u041A\u043E\u043D\u0441\u0442\u0430\u043D\u0442\u0438\u043D \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432 \u0443\u0432\u043E\u043B\u0438\u043B\u0441\u044F \u0441 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0433\u043E \u043C\u0435\u0441\u0442\u0430 \u0440\u0430\u0431\u043E\u0442\u044B \u0438 \u0432 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u043F\u043E\u0441\u0435\u043B\u0438\u043B\u0441\u044F \u0432 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439.</p><p>\u041F\u0435\u0440\u0432\u044B\u0435 \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u0438 \u0431\u044B\u043B\u0438 \u0442\u0438\u043F\u0438\u0447\u043D\u044B\u043C\u0438 \u0434\u043B\u044F \u0441\u0442\u0430\u0440\u0442\u0430\u043F\u0430: \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0439 \u0440\u0435\u043C\u043E\u043D\u0442 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u043E\u0441\u0442\u0440\u0430\u044F \u043D\u0435\u0445\u0432\u0430\u0442\u043A\u0430 \u0434\u0435\u043D\u0435\u0433 \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0430 \u0441 \u0440\u043E\u0441\u0442\u043E\u043C \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u043E\u0441\u0442\u0438 \u2013 \u043C\u0435\u0441\u0442. \u0422\u043E\u0433\u0434\u0430 \xAB\u0414\u0432\u043E\u0440 \u0421\u043E\u0442\u0440\u0443\u0434\u043D\u0435\u0439\xBB \u043C\u043E\u0433 \u043F\u0440\u0438\u043D\u044F\u0442\u044C \u043D\u0435 \u0431\u043E\u043B\u0435\u0435 5\u20137\xA0\u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0438 \u0437\u0430 \u0447\u0430\u0441 \u0440\u0430\u0431\u043E\u0442\u044B \u0431\u0440\u0430\u043B \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043F\u043B\u0430\u0442\u0443 \u2013 150 \u0440\u0443\u0431. \xAB\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u043D\u0430\u0447\u0430\u043B\u0430 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0435 \u0437\u0430\u043A\u0430\u0437\u044B, \u0437\u0430\u0447\u0430\u0441\u0442\u0443\u044E \u0441\u0438\u043B\u0430\u043C\u0438 \u0441\u0432\u043E\u0438\u0445 \u0436\u0435 \u043A\u043E\u0432\u043E\u0440\u043A\u0435\u0440\u043E\u0432\xBB,\u2009\u2013 \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442, \u0441\u0442\u043E\u044F\u0432\u0448\u0438\u0439 \u0443 \u0438\u0441\u0442\u043E\u043A\u043E\u0432 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u043F\u0440\u043E\u0435\u043A\u0442\u0430, \u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432. \u041A\u0440\u043E\u043C\u0435 \u043D\u0435\u0433\u043E, \u043A \u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u044F\u043C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430 \u043F\u0440\u0438\u0441\u043E\u0435\u0434\u0438\u043D\u0438\u043B\u0438\u0441\u044C \u0435\u0449\u0435 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432\u2011\u044D\u043D\u0442\u0443\u0437\u0438\u0430\u0441\u0442\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0430 \u0441\u0442\u0430\u0440\u0442\u0435 \u043F\u043E\u043C\u043E\u0433\u0430\u043B\u0438 \u043D\u0430 \u0434\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u043D\u044B\u0445 \u043D\u0430\u0447\u0430\u043B\u0430\u0445. \u0421\u0435\u0439\u0447\u0430\u0441 \u0437\u0430 \u0441\u0432\u043E\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043E\u043D\u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u044E\u0442 \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u0440\u0435\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0438 \u0432 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439. \u0412 \u043A\u043E\u043D\u0446\u0435 2014 \u0433. \xAB\u0414\u0432\u043E\u0440 \u0421\u043E\u0442\u0440\u0443\u0434\u043D\u0435\u0439\xBB \u0432\u043C\u0435\u0441\u0442\u043E \u0434\u0432\u0443\u0445 \u043A\u043E\u043C\u043D\u0430\u0442 \u0437\u0430\u043D\u0438\u043C\u0430\u043B \u0432 \u0442\u043E\u043C \u0436\u0435 \u043F\u043E\u0434\u0432\u0430\u043B\u0435 \u0447\u0435\u0442\u044B\u0440\u0435 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F \u0438 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u043A\u043E\u0440\u0438\u0434\u043E\u0440, \u043D\u043E \u044D\u0442\u043E\u0439 \u043F\u043B\u043E\u0449\u0430\u0434\u0438 \u043E\u043A\u0430\u0437\u0430\u043B\u043E\u0441\u044C \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E. \u0422\u043E\u0433\u0434\u0430 \u043E\u0441\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u043D\u0430\u0448\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u043E\u0440\u043D\u044B\u0435 \u0446\u0435\u0445\u0430 \u0432 \u041D\u0418\u0418\u0414\u0410\u0420\u0435 \u043D\u0430 \u041F\u0440\u0435\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u043A\u0435. \u041F\u0435\u0440\u0435\u0435\u0437\u0434 \u043F\u0440\u0438\u0432\u0435\u043B \u043A \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F\u043C \u2013 \xAB\u0414\u0432\u043E\u0440 \u0421\u043E\u0442\u0440\u0443\u0434\u043D\u0435\u0439\xBB \u043F\u0435\u0440\u0435\u0438\u043C\u0435\u043D\u043E\u0432\u0430\u043B\u0438 \u0432 <a href="/workshop/catalog/dar-truda/">\xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB</a>, \u0438 \u0441 \u044F\u043D\u0432\u0430\u0440\u044F 2016 \u0433. \u043E\u0431\u0449\u0430\u044F \u043F\u043B\u043E\u0449\u0430\u0434\u044C \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u043B\u0430\u0441\u044C \u0434\u043E 760 \u043A\u0432.\u2009\u043C.</p><p>\u041D\u0438\u043A\u0430\u043A\u0438\u0445 \u043A\u0440\u0435\u0434\u0438\u0442\u043E\u0432 \u0438 \u0438\u043D\u0432\u0435\u0441\u0442\u043E\u0440\u043E\u0432, \u0442\u043E\u043B\u044C\u043A\u043E \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0440\u043E\u0441\u0442 \u2013 \u043D\u0430 \u044D\u0442\u043E\u043C \u043A\u0440\u0435\u0434\u043E \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432 \u0438 \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432 \u043F\u044B\u0442\u0430\u044E\u0442\u0441\u044F \u043F\u043E\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u0441\u0432\u043E\u0439 \u0431\u0438\u0437\u043D\u0435\u0441. \xAB\u041E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438\u043D\u0432\u0435\u0441\u0442\u043E\u0440\u043E\u0432 \u0438 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0445 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432 \u043F\u0435\u0440\u0435\u0434 \u043A\u0435\u043C \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E\xA0\u2013 \u043E\u0434\u0438\u043D \u0438\u0437 \u043D\u0430\u0448\u0438\u0445 \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0445 \u043F\u043E\u0441\u0442\u0443\u043B\u0430\u0442\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043C\u044B \u043F\u0440\u0438\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043B\u0438\u0441\u044C \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0445 \u044D\u0442\u0430\u043F\u0430\u0445. \u041A\u0430\u043A \u0431\u044B \u0442\u044F\u0436\u0435\u043B\u043E \u043D\u0438 \u0431\u044B\u043B\u043E, \u043C\u044B \u0441\u0442\u0430\u0440\u0430\u043B\u0438\u0441\u044C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0442\u0435\u043C\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u043C\u0438 \u0438 \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043C\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u0440\u0435\u0430\u043B\u044C\u043D\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u043B\u0438\xBB,\u2009\u2013 \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0420\u043E\u043C\u0430\u043D. \u041D\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u043A\u0438 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430 \u043F\u0435\u0440\u0435\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u043A \u0432\u043D\u0435\u0448\u043D\u0435\u0439 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0435 \u2013 \u0432 \u0434\u0435\u043A\u0430\u0431\u0440\u0435 \u043F\u0440\u043E\u0448\u043B\u043E\u0433\u043E \u0433\u043E\u0434\u0430 \u043F\u0440\u043E\u0435\u043A\u0442 \u043F\u043E\u043B\u0443\u0447\u0438\u043B \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0441\u0443\u0431\u0441\u0438\u0434\u0438\u044E \u043D\u0430 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u0426\u0435\u043D\u0442\u0440\u0430 \u043C\u043E\u043B\u043E\u0434\u0435\u0436\u043D\u043E\u0433\u043E \u0438\u043D\u043D\u043E\u0432\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430, \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438 \u2013 \u0443\u0447\u0435\u0431\u043D\u043E\u0433\u043E \u0446\u0435\u043D\u0442\u0440\u0430 \xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB. \u0422\u0435\u043F\u0435\u0440\u044C \u0432 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u043C \u0446\u0435\u0445\u0435 \u0435\u0441\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0435 \u0443\u0447\u0435\u0431\u043D\u044B\u0435 \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0438 \u043E\u0431\u0449\u0435\u0439 \u0432\u043C\u0435\u0441\u0442\u0438\u043C\u043E\u0441\u0442\u044C\u044E \u0434\u043E 36\xA0\u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432. \u0421\u043A\u043E\u0440\u043E \u0446\u0435\u043D\u0442\u0440 \u0437\u0430\u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0432 \u0442\u0440\u0438 \u0441\u043C\u0435\u043D\u044B, \u0438 \u0435\u0433\u043E \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u043D\u0430\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0432\u044B\u0440\u0430\u0441\u0442\u0435\u0442 \u0434\u043E 144 \u043A\u0443\u0440\u0441\u0430\u043D\u0442\u043E\u0432.</p><p>\u041F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \xAB\u0432\u0437\u0440\u043E\u0441\u043B\u043E\u0433\u043E\xBB \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430 \u043F\u043E\u0434\u0435\u043B\u0435\u043D\u043E \u043D\u0430 \u0434\u0432\u0430 \u0437\u0430\u043B\u0430 \u2013 \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0438 \u043F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F. \u0417\u0434\u0435\u0441\u044C \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u043C\u043E\u0433\u0443\u0442 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u0434\u043E 50 \u0447\u0435\u043B\u043E\u0432\u0435\u043A. \u0412 \u043C\u0435\u0441\u044F\u0446 \xAB\u0414\u0430\u0440 \u0442\u0440\u0443\u0434\u0430\xBB \u0432 \u0441\u0440\u0435\u0434\u043D\u0435\u043C \u043F\u043E\u0441\u0435\u0449\u0430\u044E\u0442 \u0434\u043E 1000\xA0\u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432. \u0410\u0440\u0435\u043D\u0434\u0430 \u0440\u0430\u0431\u043E\u0447\u0435\u0433\u043E \u043C\u0435\u0441\u0442\u0430 \u0432 \u0447\u0430\u0441 \u0441\u0442\u043E\u0438\u0442 300\xA0\u0440\u0443\u0431., \u0432 \u0441\u0443\u0442\u043A\u0438 \u2013 1300 \u0440\u0443\u0431. \u0426\u0435\u043D\u0430 \u043C\u0435\u0441\u044F\u0447\u043D\u043E\u0433\u043E \u0430\u0431\u043E\u043D\u0435\u043C\u0435\u043D\u0442\u0430 \u0440\u0430\u0432\u043D\u0430 8000\xA0\u0440\u0443\u0431. \u0415\u0441\u0442\u044C \u044D\u043A\u0441\u043A\u043B\u044E\u0437\u0438\u0432\u043D\u043E\u0435 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u2013 \u043C\u043E\u0436\u043D\u043E \u0430\u0440\u0435\u043D\u0434\u043E\u0432\u0430\u0442\u044C \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u044C\u043D\u0443\u044E \u044F\u0447\u0435\u0439\u043A\u0443 \u043D\u0430 7 \u043A\u0432. \u043C \u043F\u043E \u0442\u0430\u0440\u0438\u0444\u0443 \xAB\u0421\u0432\u043E\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F\xBB \u0437\u0430 15\u2009000 \u0440\u0443\u0431. \u0432 \u043C\u0435\u0441\u044F\u0446. \u0417\u0430 2015 \u0433. \u043E\u0431\u043E\u0440\u043E\u0442 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 7\xA0\u043C\u043B\u043D \u0440\u0443\u0431., \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u0435\u0435 \u0440\u0435\u043D\u0442\u0430\u0431\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0441\u0442\u0430\u0432\u0438\u043B\u0430 11\u201312%. \xAB\u042D\u0442\u0438 \u0446\u0438\u0444\u0440\u044B \u043D\u0435\u043B\u044C\u0437\u044F \u0442\u0438\u0440\u0430\u0436\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0434\u0440\u0443\u0433\u0438\u0435 \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438,\u2009\u2013 \u043E\u0442\u043C\u0435\u0447\u0430\u0435\u0442 \u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432.\u2009\u2013 \u0412 \u0420\u043E\u0441\u0441\u0438\u0438 \u0442\u0430\u043A\u043E\u0433\u043E \u0432\u0438\u0434\u0430 \u0431\u0438\u0437\u043D\u0435\u0441\u0430 \u043F\u043E\u043A\u0430 \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442. \u042D\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0441\u0447\u0438\u0442\u0430\u0442\u044C \u043A\u0430\u043A \u043F\u043B\u044E\u0441\u043E\u043C (\u043C\u044B \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C \u0441\u0435\u0431\u044F \u043F\u0435\u0440\u0432\u043E\u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0442\u0435\u043B\u044F\u043C\u0438 \u043D\u043E\u0432\u043E\u0439 \u043D\u0438\u0448\u0438), \u0442\u0430\u043A \u0438 \u043C\u0438\u043D\u0443\u0441\u043E\u043C: \u0444\u0430\u043A\u0442 \u043F\u0440\u0438\u0431\u044B\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u2013 \u0432\u043E \u043C\u043D\u043E\u0433\u043E\u043C \u0432\u043E\u043F\u0440\u043E\u0441 \u0443\u0434\u0430\u0447\u0438\xBB.</p><p>\u0420\u0435\u043D\u0442\u0430\u0431\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u043E\u0433\u043E \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u0430, \u043F\u043E \u0435\u0433\u043E \u0441\u043B\u043E\u0432\u0430\u043C, \u043D\u0443\u043B\u0435\u0432\u0430\u044F. \xAB\u041D\u043E, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u043D\u0438\u0437\u043A\u0443\u044E \u043F\u0440\u0438\u0431\u044B\u043B\u044C, \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u2013 \u043D\u0430\u0448\u0430 \u0432\u0438\u0437\u0438\u0442\u043D\u0430\u044F \u043A\u0430\u0440\u0442\u043E\u0447\u043A\u0430\xBB,\u2009\u2013 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0420\u043E\u043C\u0430\u043D \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432 \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u0421\u043A\u0432\u043E\u0440\u0446\u043E\u0432\u0430 \u0438 \u0424\u0430\u0440\u0430\u0434\u0436\u0443\u043B\u043B\u0430\u0435\u0432\u0430 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0442\u044C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433 \u0434\u0430\u043B\u044C\u0448\u0435. \u041E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0434\u043E\u0445\u043E\u0434 \xAB\u0414\u0430\u0440\u0443 \u0442\u0440\u0443\u0434\u0430\xBB \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 \u0441\u0442\u043E\u043B\u044F\u0440\u043D\u044B\u0435 \u0437\u0430\u043A\u0430\u0437\u044B. \u0412 \u043D\u043E\u0432\u043E\u043C \u0433\u043E\u0434\u0443 \u0435\u0433\u043E \u0441\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u0438 \u0434\u0435\u043B\u0430\u044E\u0442 \u0441\u0442\u0430\u0432\u043A\u0443 \u043D\u0430 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u0442\u0434\u0435\u043B\u0430. \u041F\u0440\u0438 \u0438\u0434\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0440\u0430\u0441\u043A\u043B\u0430\u0434\u0435 \u0441 \u043F\u043E\u043C\u0435\u0442\u043A\u043E\u0439 \xAB\u0421\u043E\u0437\u0434\u0430\u043D\u043E \u0432 \xAB\u0414\u0430\u0440\u0435 \u0442\u0440\u0443\u0434\u0430\xBB \u0432 \u0440\u043E\u0437\u043D\u0438\u0446\u0435 \u043F\u043E\u044F\u0432\u044F\u0442\u0441\u044F \u043C\u0435\u0431\u0435\u043B\u044C, \u0441\u0443\u0432\u0435\u043D\u0438\u0440\u044B \u0438 \u0434\u0435\u043A\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u044B\u0435 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u044B \u0438\u043D\u0442\u0435\u0440\u044C\u0435\u0440\u0430. \xAB\u0417\u0434\u0435\u0441\u044C \u0432\u0430\u0436\u043D\u044B\u043C \u043F\u043E\u0434\u0441\u043F\u043E\u0440\u044C\u0435\u043C \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0446\u0438\u0444\u0440\u043E\u0432\u043E\u0433\u043E \u043E\u0442\u0434\u0435\u043B\u0430, \u043E\u0441\u043D\u0430\u0449\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u044B\u0441\u043E\u043A\u043E\u0442\u043E\u0447\u043D\u044B\u043C \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435\u043C, \u043F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E\u2009\u2013 \u043B\u0430\u0437\u0435\u0440\u043D\u044B\u043C\u0438 \u0438 \u0427\u041F\u0423-\u0444\u0440\u0435\u0437\u0435\u0440\u043D\u044B\u043C\u0438 \u0441\u0442\u0430\u043D\u043A\u0430\u043C\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0437\u0430\u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 1\u20132 \u043C\u0435\u0441\u044F\u0446\u0430\xBB,\u2009\u2013 \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442 \u0411\u043E\u043D\u0434\u0430\u0440\u0435\u0432. \u0421\u0442\u0430\u043D\u0435\u0442 \u043B\u0438 \u044D\u0442\u043E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0431\u044B\u043B\u044C\u043D\u044B\u043C? \u0414\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u043D\u0435\u0442, \u043D\u0438\u0447\u0435\u0433\u043E \u0441\u0442\u0440\u0430\u0448\u043D\u043E\u0433\u043E \u2013 \u0443 \xAB\u0414\u0430\u0440\u0430 \u0442\u0440\u0443\u0434\u0430\xBB \u0435\u0449\u0435 \u043C\u043D\u043E\u0433\u043E \u0438\u0434\u0435\u0439, \u043A\u0430\u043A \u0437\u0430\u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C \u043D\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0438\u0442\u044C.</p><p>\u0410\u0432\u0442\u043E\u0440 \u0441\u0442\u0430\u0442\u044C\u0438:\xA0<strong>\u041E\u043B\u044C\u0433\u0430 \u0413\u0440\u0438\u043D\u0435\u0432\u0438\u0447</strong></p><p>\u041E\u0440\u0438\u0433\u0438\u043D\u0430\u043B \u0441\u0442\u0430\u0442\u044C\u0438:\xA0<a href="http://ko.ru/keys/item/131891-kamen-nozhnitsy-bumaga" class="external-link" target="_blank" rel="noopener noreferrer">http://ko.ru/keys/item/131891-kamen-nozhnitsy-bumaga</a></p>',25),s=[o];function n(i,h,c,d,l,_){return e(),a("div",null,s)}var S=t(p,[["render",n]]);export{u as __pageData,S as default};
